 120→const normalizeApiPath = (path = '') => (
 121→    String(path).startsWith('/api/')
 122→        ? String(path).slice(4)
 123→        : String(path)
 124→);
 125→
 126→const canonicalizeMetricsPath = (rawPath = '') => {
 127→    const normalized = normalizeApiPath(rawPath);
 128→    return normalized
 129→        .replace(/\/[0-9a-f]{8}-[0-9a-f-]{27,}(?=\/|$)/ig, '/:id')
 130→        .replace(/\/\d+(?=\/|$)/g, '/:id');
 131→};
