 133→const isPersonalizedGetRequest = (req) => {
 134→    if (req?.headers?.authorization) {
 135→        return true;
 136→    }
 137→
 138→    const userId = String(req?.query?.userId || '').trim();
 139→    const loggedInUserId = String(req?.query?.loggedInUserId || '').trim();
 140→    return Boolean(userId || loggedInUserId);
 141→};
