 147→const classifyStatusBucket = (statusCode) => {
 148→    if (statusCode >= 200 && statusCode < 300) return '2xx';
 149→    if (statusCode >= 300 && statusCode < 400) return '3xx';
 150→    if (statusCode >= 400 && statusCode < 500) return '4xx';
 151→    if (statusCode >= 500 && statusCode < 600) return '5xx';
 152→    return 'other';
 153→};
