 155→const normalizeWhitespace = (value) => String(value ?? '')
 156→    .replace(/\s+/g, ' ')
 157→    .trim();
 158→
 159→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 160→    const normalized = normalizeWhitespace(value);
 161→    if (!normalized) return '';
 162→    if (normalized.length <= maxLength) return normalized;
 163→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 164→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 165→};
