 885→        debugPayload.stage = 'fetching_upstream';
 886→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 887→        debugPayload.stage = 'upstream_loaded';
 888→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 889→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 890→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 891→
 892→        debugPayload.stage = 'converting_image';
 893→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 894→        debugPayload.stage = 'converted_image';
 895→        debugPayload.ok = true;
 896→        debugPayload.reason = 'ok';
 897→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 898→
 899→        if (debugMode) {
 900→            return sendShareImageDebug(res, debugPayload);
 901→        }
 902→
 903→        res.set('Content-Type', 'image/jpeg');
 904→        res.set('Cache-Control', 'public, max-age=3600');
 905→        return res.send(ogImageBuffer);
 906→    } catch (err) {
 907→        debugPayload.stage = 'error';
 908→        debugPayload.reason = err?.message || 'unknown_error';
 909→        console.error('share image route error:', err?.message || err);
