  1→import supabase from "./supabase.js";
  2→
  3→const MILESTONES = [7, 14, 30, 50, 100];
  4→
  5→/**
  6→ * Get a user's current streak data.
  7→ */
  8→export const getStreakService = async (userId) => {
  9→    if (!userId) return null;
 10→
 11→    const { data, error } = await supabase
 12→        .from('writing_streaks')
 13→        .select('*')
 14→        .eq('user_id', userId)
 15→        .maybeSingle();
 16→
 17→    if (error) {
 18→        console.error('error fetching streak:', error.message);
 19→        return null;
 20→    }
 21→
 22→    if (!data) {
 23→        return {
 24→            current_streak: 0,
 25→            longest_streak: 0,
 26→            last_publish_date: null,
 27→            freeze_available: false,
 28→        };
 29→    }
 30→
 31→    // Check if streak is still active (not expired)
 32→    const today = getUTCDateString();
 33→    const gap = data.last_publish_date ? daysBetween(data.last_publish_date, today) : null;
 34→
 35→    // If gap > 2 days (or > 3 with no freeze), streak has silently expired
 36→    if (gap !== null && gap > 2) {
 37→        return {
 38→            current_streak: 0,
 39→            longest_streak: data.longest_streak,
 40→            last_publish_date: data.last_publish_date,
 41→            freeze_available: data.freeze_available,
 42→        };
 43→    }
 44→
 45→    return {
 46→        current_streak: data.current_streak,
 47→        longest_streak: data.longest_streak,
 48→        last_publish_date: data.last_publish_date,
 49→        freeze_available: data.freeze_available,
 50→    };
 51→};
 52→
 53→/**
 54→ * Record a publish event for streak tracking.
 55→ * Called after a new journal/opinion/chapter is published.
 56→ * Returns { streakData, milestone } where milestone is 7|14|30|50|100|null.
 57→ */
 58→export const recordPublishForStreak = async (userId) => {
 59→    if (!userId) return { streakData: null, milestone: null };
 60→
 61→    const today = getUTCDateString();
 62→
 63→    // Fetch existing streak row
 64→    const { data: existing, error: fetchErr } = await supabase
 65→        .from('writing_streaks')
 66→        .select('*')
 67→        .eq('user_id', userId)
 68→        .maybeSingle();
 69→
 70→    if (fetchErr) {
 71→        console.error('error fetching streak for record:', fetchErr.message);
 72→        return { streakData: null, milestone: null };
 73→    }
 74→
 75→    // No existing row → first publish ever
 76→    if (!existing) {
 77→        const newRow = {
 78→            user_id: userId,
 79→            current_streak: 1,
 80→            longest_streak: 1,
 81→            last_publish_date: today,
 82→            freeze_available: false,
 83→            updated_at: new Date().toISOString(),
 84→        };
 85→
 86→        const { error: insertErr } = await supabase
 87→            .from('writing_streaks')
 88→            .insert(newRow);
 89→
 90→        if (insertErr) {
 91→            console.error('error inserting streak:', insertErr.message);
 92→            return { streakData: null, milestone: null };
 93→        }
 94→
 95→        return { streakData: newRow, milestone: null };
 96→    }
 97→
 98→    // Already published today → no-op
 99→    if (existing.last_publish_date === today) {
100→        return { streakData: existing, milestone: null };
101→    }
102→
103→    const gap = daysBetween(existing.last_publish_date, today);
104→
105→    let newStreak = existing.current_streak;
106→    let freezeAvailable = existing.freeze_available;
107→    let freezeUsedDate = existing.freeze_used_date;
108→
109→    if (gap === 1) {
110→        // Consecutive day
111→        newStreak += 1;
112→    } else if (gap === 2 && freezeAvailable) {
113→        // Missed exactly 1 day, auto-use freeze
114→        newStreak += 1;
115→        freezeAvailable = false;
116→        freezeUsedDate = today;
117→    } else {
118→        // Streak broken
119→        newStreak = 1;
120→    }
121→
122→    const newLongest = Math.max(existing.longest_streak, newStreak);
123→
124→    // Grant a new freeze every 7 days of streak (if not already available)
125→    if (!freezeAvailable && newStreak > 0 && newStreak % 7 === 0) {
126→        const lastGranted = existing.freeze_last_granted;
127→        if (!lastGranted || lastGranted !== today) {
128→            freezeAvailable = true;
129→        }
130→    }
131→
132→    const updatePayload = {
133→        current_streak: newStreak,
134→        longest_streak: newLongest,
135→        last_publish_date: today,
136→        freeze_available: freezeAvailable,
137→        freeze_used_date: freezeUsedDate,
138→        freeze_last_granted: freezeAvailable ? today : existing.freeze_last_granted,
139→        updated_at: new Date().toISOString(),
140→    };
141→
142→    const { error: updateErr } = await supabase
143→        .from('writing_streaks')
144→        .update(updatePayload)
145→        .eq('user_id', userId);
146→
147→    if (updateErr) {
148→        console.error('error updating streak:', updateErr.message);
149→        return { streakData: null, milestone: null };
150→    }
151→
152→    // Check for milestone
153→    const milestone = MILESTONES.includes(newStreak) ? newStreak : null;
154→
155→    return {
156→        streakData: { ...existing, ...updatePayload },
157→        milestone,
158→    };
159→};
160→
161→// ─── Helpers ───
162→
163→function getUTCDateString() {
164→    const now = new Date();
165→    return now.toISOString().split('T')[0]; // 'YYYY-MM-DD'
166→}
167→
168→function daysBetween(dateStrA, dateStrB) {
169→    const a = new Date(dateStrA + 'T00:00:00Z');
170→    const b = new Date(dateStrB + 'T00:00:00Z');
171→    return Math.round((b - a) / (1000 * 60 * 60 * 24));
172→}
