229→    const nowIso = new Date().toISOString();
230→    if(week.status !== "active" || nowIso < week.week_start || nowIso >= week.week_end){
231→        throw {status: 409, error: "freedom wall week is not active"};
232→    }
233→
234→    return week;
235→};
