311→export const getFreedomWallItemsService = async(weekId, limit, cursor, types) => {
312→    if(!weekId){
313→        throw {status: 400, error: "weekId is required"};
314→    }
315→
316→    const parsedLimit = parseLimit(limit);
317→    const typeFilters = parseTypeFilters(types);
318→
319→    let query = supabase
320→        .from("freedom_wall_items")
321→        .select(selectItemColumns)
322→        .eq("week_id", weekId)
323→        .is("deleted_at", null)
324→        .order("z_index", {ascending: true})
325→        .order("created_at", {ascending: true})
326→        .order("id", {ascending: true})
327→        .limit(parsedLimit + 1);
328→
329→    if(cursor){
330→        query = query.gt("created_at", cursor);
331→    }
332→
333→    if(typeFilters.length > 0){
334→        query = query.in("item_type", typeFilters);
335→    }
336→
337→    const {data: items, error: itemsError} = await query;
338→
339→    if(itemsError){
340→        console.error("supabase error while reading freedom wall items:", itemsError.message);
341→        throw {status: 500, error: "failed to fetch freedom wall items"};
342→    }
343→
344→    const hasMore = (items || []).length > parsedLimit;
345→    const slicedItems = hasMore ? items.slice(0, parsedLimit) : (items || []);
346→    const nextCursor = hasMore
347→        ? slicedItems[slicedItems.length - 1]?.created_at || null
348→        : null;
349→
350→    return {
351→        data: slicedItems,
352→        hasMore: hasMore,
353→        nextCursor: nextCursor
354→    };
355→};
