396→export const updateFreedomWallItemService = async({itemId, payload, zIndex, userId}) => {
397→    if(!userId){
398→        throw {status: 401, error: "not authorized"};
399→    }
400→
401→    if(!itemId){
402→        throw {status: 400, error: "itemId is required"};
403→    }
404→
405→    if(payload === undefined && zIndex === undefined){
406→        throw {status: 400, error: "payload or zIndex is required"};
407→    }
408→
409→    const {data: existingItem, error: existingItemError} = await supabase
410→        .from("freedom_wall_items")
411→        .select("id, week_id, user_id, item_type, payload, z_index")
412→        .eq("id", itemId)
413→        .is("deleted_at", null)
414→        .maybeSingle();
415→
416→    if(existingItemError){
417→        console.error("supabase error while reading freedom wall item:", existingItemError.message);
418→        throw {status: 500, error: "failed to read freedom wall item"};
419→    }
420→
421→    if(!existingItem?.id){
422→        throw {status: 404, error: "freedom wall item not found"};
423→    }
424→
425→    if(String(existingItem.user_id) !== String(userId)){
426→        throw {status: 403, error: "not allowed to edit this freedom wall item"};
427→    }
428→
429→    await assertActiveWeek(existingItem.week_id);
430→
431→    const updatePayload = {};
432→    if(payload !== undefined){
433→        const mergedPayload = {
434→            ...(existingItem.payload || {}),
435→            ...(payload || {})
436→        };
437→        updatePayload.payload = sanitizePayloadByType(existingItem.item_type, mergedPayload);
438→    }
439→
440→    if(zIndex !== undefined){
441→        updatePayload.z_index = clamp(normalizeNumber(zIndex, existingItem.z_index || 0), -100000, 100000);
442→    }
443→
444→    const {data: updatedItem, error: updateError} = await supabase
445→        .from("freedom_wall_items")
446→        .update(updatePayload)
447→        .eq("id", itemId)
448→        .select(selectItemColumns)
449→        .single();
450→
451→    if(updateError){
452→        console.error("supabase error while updating freedom wall item:", updateError.message);
453→        throwMappedDatabaseError(updateError, "failed to update freedom wall item");
454→    }
455→
456→    return {item: updatedItem};
457→};
